chrome.action.onClicked.addListener(e=>{chrome.sidePanel.open({tabId:e.id})});chrome.runtime.onMessage.addListener((e,o,r)=>{if(e.type!=="MYT_TIMELINE_EVENT")return;const s=e.payload;return chrome.storage.session.get("myt_events",t=>{const n=t.myt_events||[];n.push(s),chrome.storage.session.set({myt_events:n},()=>{chrome.runtime.sendMessage({type:"NEW_TIMELINE_EVENT",payload:s})})}),!0});
